import SockJS from 'sockjs-client'
import Stomp from 'webstomp-client'
import { getToken } from '@/utils/auth'
import store from '@/store'

class WebSocketService {
  constructor() {
    this.socket = null
    this.stompClient = null
    this.connected = false
    this.subscriptions = []
    this.reconnectAttempts = 0
    this.maxReconnectAttempts = 5
    this.reconnectTimeout = null
  }

  /**
   * 连接WebSocket服务器
   */
  connect() {
    if (this.connected || this.socket) {
      console.log('WebSocket已连接或正在连接中')
      return
    }

    console.log('正在连接WebSocket服务器...')
    
    // 创建SockJS实例
    this.socket = new SockJS('/ws')
    
    // 创建STOMP客户端
    this.stompClient = Stomp.over(this.socket)
    
    // 禁用STOMP调试输出
    this.stompClient.debug = () => {}
    
    // 获取认证Token
    const token = getToken()
    
    // 连接头信息
    const headers = {
      Authorization: token ? `Bearer ${token}` : ''
    }
    
    // 连接WebSocket服务器
    this.stompClient.connect(
      headers,
      frame => {
        this.connected = true
        this.reconnectAttempts = 0
        console.log('WebSocket连接成功:', frame)
        
        // 订阅系统设置变更主题
        this.subscribe('/topic/settings', this.handleSettingChange)
        
        // 订阅系统通知主题
        this.subscribe('/topic/notifications', this.handleNotification)
      },
      error => {
        console.error('WebSocket连接错误:', error)
        this.disconnect()
        
        // 尝试重新连接
        this.reconnect()
      }
    )
  }
  
  /**
   * 重新连接WebSocket
   */
  reconnect() {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      console.log('已达到最大重连次数，停止重连')
      return
    }
    
    this.reconnectAttempts++
    const delay = Math.min(30000, 1000 * Math.pow(2, this.reconnectAttempts)) // 指数退避策略
    
    console.log(`将在${delay/1000}秒后尝试重新连接，尝试次数：${this.reconnectAttempts}`)
    
    if (this.reconnectTimeout) {
      clearTimeout(this.reconnectTimeout)
    }
    
    this.reconnectTimeout = setTimeout(() => {
      console.log('正在尝试重新连接...')
      this.connect()
    }, delay)
  }
  
  /**
   * 断开WebSocket连接
   */
  disconnect() {
    if (this.stompClient) {
      // 取消所有订阅
      this.subscriptions.forEach(subscription => {
        if (subscription && typeof subscription.unsubscribe === 'function') {
          subscription.unsubscribe()
        }
      })
      this.subscriptions = []
      
      // 断开连接
      if (this.stompClient.connected) {
        this.stompClient.disconnect()
      }
      this.stompClient = null
    }
    
    if (this.socket) {
      this.socket.close()
      this.socket = null
    }
    
    this.connected = false
  }
  
  /**
   * 订阅主题
   * @param {string} destination 目标主题
   * @param {function} callback 回调函数
   * @returns {object} 订阅对象
   */
  subscribe(destination, callback) {
    if (!this.connected || !this.stompClient) {
      console.warn('WebSocket未连接，无法订阅:', destination)
      return null
    }
    
    console.log('订阅主题:', destination)
    const subscription = this.stompClient.subscribe(destination, message => {
      try {
        const data = JSON.parse(message.body)
        callback(data)
      } catch (error) {
        console.error('解析消息出错:', error, message.body)
      }
    })
    
    this.subscriptions.push(subscription)
    return subscription
  }
  
  /**
   * 发送消息到服务器
   * @param {string} destination 目标地址
   * @param {object} body 消息内容
   */
  send(destination, body) {
    if (!this.connected || !this.stompClient) {
      console.warn('WebSocket未连接，无法发送消息:', destination)
      return
    }
    
    this.stompClient.send(
      destination,
      JSON.stringify(body),
      { 
        'content-type': 'application/json',
        Authorization: getToken() ? `Bearer ${getToken()}` : ''
      }
    )
  }
  
  /**
   * 处理设置变更消息
   * @param {object} data 消息数据
   */
  handleSettingChange(data) {
    console.log('收到设置变更:', data)
    
    // 根据设置类型处理
    if (data.type === 'SETTING_CHANGED') {
      // 派发Vuex Action来更新设置
      store.dispatch('settings/updateSetting', {
        key: data.key,
        value: data.value,
        group: data.group
      })
      
      // 如果是特定设置，执行特定操作
      switch (data.key) {
        case 'system.logo':
          // 更新系统Logo
          store.dispatch('settings/refreshSystemLogo')
          break
        case 'system.name':
          // 更新系统名称
          store.dispatch('settings/refreshSystemName')
          break
        default:
          // 其他设置更新
          break
      }
    }
  }
  
  /**
   * 处理系统通知消息
   * @param {object} data 消息数据
   */
  handleNotification(data) {
    console.log('收到系统通知:', data)
    
    if (data.type === 'SYSTEM_NOTIFICATION') {
      // 显示系统通知
      store.dispatch('notification/showNotification', {
        message: data.message,
        type: 'info'
      })
    }
  }
}

// 创建单例实例
const wsService = new WebSocketService()

export default wsService 