/**
 * HTTP请求封装模块
 * 基于axios的请求库，统一处理HTTP请求和响应
 */
import axios from 'axios'
import { getToken, removeToken, removeUser, setToken } from '@/utils/auth'
import { message } from 'ant-design-vue'
import router from '@/router'

/**
 * 创建axios实例
 * 配置基础URL、超时时间、跨域凭证和默认请求头
 */
const request = axios.create({
  baseURL: process.env.VUE_APP_BASE_API || 'http://localhost:8080',
  timeout: 60000,  // 60秒超时时间
  withCredentials: true,  // 允许跨域请求携带凭证
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  }
})

/**
 * 请求拦截器
 * 在发送请求前自动添加认证令牌
 */
request.interceptors.request.use(
  config => {
    const token = getToken()
    console.log('Request URL:', config.url)
    console.log('Current token:', token)
    
    if (token) {
      // 确保Bearer token格式正确
      config.headers['Authorization'] = `Bearer ${token}`
      console.log('Setting Authorization header:', config.headers['Authorization'])
    } else {
      console.log('No token found')
    }
    
    return config
  },
  error => {
    console.error('Request interceptor error:', error)
    return Promise.reject(error)
  }
)

/**
 * 响应拦截器
 * 处理响应数据和统一处理错误码
 * 可以处理令牌刷新和会话过期等场景
 */
request.interceptors.response.use(
  response => {
    // 处理令牌刷新
    const newToken = response.headers['new-token']
    if (newToken) {
      setToken(newToken)
    }
    return response
  },
  error => {
    // 统一处理HTTP错误状态码
    if (error.response) {
      switch (error.response.status) {
        case 400:
          message.error(error.response.data.message || '请求参数错误')
          break
        case 401:
          // 未授权，清除用户信息并跳转到登录页
          message.error('未授权，请重新登录')
          removeToken()
          removeUser()
          router.push('/login')
          break
        case 403:
          message.error('拒绝访问')
          break
        case 404:
          message.error('请求错误，未找到该资源')
          break
        case 500:
          message.error('服务器端出错')
          break
        default:
          message.error(error.response.data.message || '操作失败，请重试')
      }
    } else {
      // 网络错误或请求被取消
      message.error('网络错误，请检查网络连接')
    }
    return Promise.reject(error)
  }
)

export default request 